;(function($){if(!$){return;}$.fn.lazyload=function(opts){var settings=$.extend({effect:"show"},opts||{});return this.each(function(){var $img=$(this);var src=$img.attr("data-original")||$img.attr("data-src");if(src&&!$img.attr("src")){$img.attr("src",src);}if(settings.effect==="fadeIn"){$img.hide().fadeIn(200);}});};})(window.jQuery);
